import { Injectable, Logger, LogLevel } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import _ from 'lodash';
import moment from 'moment';

import { Coded } from '@/app/common/decorators';
import { BaseProvider } from '@/app/providers/base-provider';

export declare class Config {
  readonly appName: string;
  readonly appSecretKey: string;
  readonly appEnv: 'local' | 'develop' | 'staging' | 'production';
  readonly serverPort: string;
  readonly appBaseUrl: string;
  readonly webBaseUrl: string;

  readonly logLevel: string;
  readonly logFile: string;

  readonly defaultTokenExpirationSeconds: number;

  readonly dbHost: string;
  readonly dbPort: number;
  readonly dbDatabase: string;
  readonly dbUsername: string;
  readonly dbPassword: string;

  readonly emailUser: string;
  readonly sgApiKey: string;
  readonly emailFromAddress: string;
  readonly emailBccUser: string;
  readonly emailHost: string;
  readonly emailPort: string;

  readonly slackApiHost: string;
  readonly slackAuthToken: string;

  readonly serverCommunicationSalt: string;

  readonly jwtSecret: string;

  readonly cognitoPoolId: string;
  readonly cognitoClientId: string;
  readonly cognitoRegion: string;
  readonly cognitoLocalEndpoint: string;

  readonly analyzeServerUrl: string;
  readonly analyzeKey: string;
  readonly internalIfSalt: string;

  readonly awsDefaultBucket: string;
  readonly awsS3Region: string;
  readonly awsS3LocalEndpoint: string;

  readonly stripeSecretKey: string;
  readonly stripeWebhookSecret: string;

  readonly appleAppStoreApiKey: string;
  readonly appleAppStoreKeyId: string;
  readonly appleAppStoreIssuerId: string;
  readonly appleAppStoreBundleId: string;
  readonly appleAppStoreAppAppleId?: string;

  readonly bedrockModelId: string;
  readonly bedrockModelRegion: string;
  readonly aiCoachUserPromptS3Key: string;
  readonly aiCoachSystemPromptS3Key: string;

  readonly appLastUpdateDatetime: Date;
}

@Coded('PVCFG')
@Injectable()
export class ConfigProvider extends BaseProvider {
  private readonly logger = new Logger(ConfigProvider.name);

  private _config: Config;

  constructor(private readonly configService: ConfigService) {
    super();
    const dt = this.configService.get<string>('APP_LAST_UPDATE_DATETIME');
    this._config = {
      appName: this.getOrShowError<string>('APP_NAME'),
      appSecretKey: this.getOrShowError<string>('APP_SECRET_KEY'),
      appEnv: this.getOrShowError<string>('APP_ENV'),
      serverPort: this.getOrShowError<number>('SERVER_PORT', {
        cast: _.toNumber,
      }),
      appBaseUrl: this.getOrShowError<string>('APP_BASE_URL'),
      webBaseUrl: this.getOrShowError<string>('WEB_BASE_URL'),

      logLevel: this.getOrShowError<LogLevel>('LOG_LEVEL', { default: 'log' }),
      logFile: this.getOrShowError<string>('LOG_FILE', { default: null }),

      defaultTokenExpirationSeconds: this.getOrShowError<number>(
        'DEFAULT_TOKEN_EXPIRATION_SECONDS',
        { default: 86400 },
      ),

      dbHost: this.getOrShowError<string>('DB_HOST', { default: null }),
      dbPort: this.getOrShowError<number>('DB_PORT', { cast: _.toNumber }),
      dbDatabase: this.getOrShowError<string>('DB_DATABASE', { default: null }),
      dbUsername: this.getOrShowError<string>('DB_USERNAME', { default: null }),
      dbPassword: this.getOrShowError<string>('DB_PASSWORD', { default: null }),

      emailUser: this.getOrShowError<string>('EMAIL_USER', { default: null }),
      sgApiKey: this.getOrShowError<string>('SENDGRID_API_KEY', {
        default: null,
      }),
      emailFromAddress: this.getOrShowError<string>('EMAIL_FROM_ADDRESS', {
        default: null,
      }),
      emailBccUser: this.getOrShowError<string>('EMAIL_BCC_USER', {
        default: null,
      }),
      emailHost: this.getOrShowError<string>('EMAIL_HOST', { default: null }),
      emailPort: this.getOrShowError<string>('EMAIL_PORT', { default: null }),

      slackApiHost: this.getOrShowError<string>('SLACK_API_HOST', {
        default: null,
      }),
      slackAuthToken: this.getOrShowError<string>('SLACK_AUTH_TOKEN', {
        default: null,
      }),

      serverCommunicationSalt: this.getOrShowError<string>(
        'SERVER_COMMUNICATION_SALT',
        { default: '' },
      ),

      jwtSecret: this.getOrShowError<string>('JWT_SECRET'),

      cognitoPoolId: this.getOrShowError<string>('COGNITO_POOL_ID'),
      cognitoClientId: this.getOrShowError<string>('COGNITO_CLIENT_ID'),
      cognitoRegion: this.getOrShowError<string>('COGNITO_REGION'),
      cognitoLocalEndpoint: this.getOrShowError<string>(
        'COGNITO_LOCAL_ENDPOINT',
        { default: '' },
      ),

      analyzeServerUrl: this.getOrShowError<string>('ANALYZE_SERVER_URL'),
      analyzeKey: this.getOrShowError<string>('ANALYZE_SERVER_ACCESS_KEY'),
      internalIfSalt: this.getOrShowError<string>('INTERNAL_IF_SALT'),

      awsDefaultBucket: this.getOrShowError<string>('AWS_DEFAULT_BUCKET'),
      awsS3Region: this.getOrShowError<string>('AWS_S3_REGION'),
      awsS3LocalEndpoint: this.getOrShowError<string>('AWS_S3_LOCAL_ENDPOINT', {
        default: '',
      }),

      stripeSecretKey: this.getOrShowError<string>('STRIPE_SECRET_KEY', {
        default: null,
      }),
      stripeWebhookSecret: this.getOrShowError<string>(
        'STRIPE_WEBHOOK_SECRET',
        {
          default: null,
        },
      ),

      appleAppStoreApiKey: this.getOrShowError<string>(
        'APPLE_APP_STORE_API_KEY',
        { default: '' },
      ),
      appleAppStoreKeyId: this.getOrShowError<string>(
        'APPLE_APP_STORE_KEY_ID',
        { default: '' },
      ),
      appleAppStoreIssuerId: this.getOrShowError<string>(
        'APPLE_APP_STORE_ISSUER_ID',
        { default: '' },
      ),
      appleAppStoreBundleId: this.getOrShowError<string>(
        'APPLE_APP_STORE_BUNDLE_ID',
        { default: '' },
      ),

      bedrockModelRegion: this.getOrShowError<string>('BEDROCK_MODEL_REGION', {
        default: 'us-east-1',
      }),
      bedrockModelId: this.getOrShowError<string>('BEDROCK_MODEL_ID', {
        default: 'us.anthropic.claude-opus-4-1-20250805-v1:0',
      }),

      appLastUpdateDatetime: dt ? moment(dt).toDate() : new Date(),

      aiCoachUserPromptS3Key: 'ai-coach-report/prompt/user-template.txt',
      aiCoachSystemPromptS3Key: 'ai-coach-report/prompt/system-template.txt',
    };
  }

  get config() {
    return this._config;
  }

  private getOrShowError<T>(
    key,
    opts: { default?; cast?: ((v: T) => T) | null } = {
      default: undefined,
      cast: null,
    },
  ) {
    const val = this.configService.get<T>(key);
    if (val) {
      if (opts.cast) {
        return opts.cast(val);
      }
      return val;
    } else if (opts.default !== undefined) {
      return opts.default;
    }
    this.logger.error(
      `Insufficient environment value for key: ${key}. Check your .env`,
    );
    return null;
  }
}

