        'SERVER_COMMUNICATION_SALT',
        { default: '' },
      ),

      jwtSecret: this.getOrShowError<string>('JWT_SECRET'),

      cognitoPoolId: this.getOrShowError<string>('COGNITO_POOL_ID'),
      cognitoClientId: this.getOrShowError<string>('COGNITO_CLIENT_ID'),
