        'COGNITO_LOCAL_ENDPOINT',
        { default: '' },
      ),

      analyzeServerUrl: this.getOrShowError<string>('ANALYZE_SERVER_URL'),
      analyzeKey: this.getOrShowError<string>('ANALYZE_SERVER_ACCESS_KEY'),
      internalIfSalt: this.getOrShowError<string>('INTERNAL_IF_SALT'),

      awsDefaultBucket: this.getOrShowError<string>('AWS_DEFAULT_BUCKET'),
      awsS3Region: this.getOrShowError<string>('AWS_S3_REGION'),
      awsS3LocalEndpoint: this.getOrShowError<string>('AWS_S3_LOCAL_ENDPOINT', {
        default: '',
      }),

      stripeSecretKey: this.getOrShowError<string>('STRIPE_SECRET_KEY', {
        default: null,
